def is_multiply_prime(a):
    """Write a function that returns true if the given number is the multiplication of 3 prime numbers
    and false otherwise.
    Knowing that (a) is less then 100. 
    Example:
    is_multiply_prime(30) == True
    30 = 2 * 3 * 5
    """
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    # Find all prime factors of a (with multiplicity)
    factors = []
    temp = a
    for i in range(2, a + 1):
        while temp % i == 0:
            factors.append(i)
            temp //= i
        if temp == 1:
            break

    # Check if all factors are prime and there are exactly 3
    if len(factors) != 3:
        return False

    for f in factors:
        if not is_prime(f):
            return False

    return True
