def encode(message):
    """
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    vowels = 'aeiouAEIOU'
    vowel_map = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    result = []
    for char in message:
        if char in vowels:
            # Replace vowel with the letter 2 places ahead, then swap case
            new_char = vowel_map[char]
            # Swap case of the new character
            if new_char.islower():
                new_char = new_char.upper()
            else:
                new_char = new_char.lower()
            result.append(new_char)
        else:
            # Swap case of non-vowel characters
            if char.islower():
                result.append(char.upper())
            elif char.isupper():
                result.append(char.lower())
            else:
                result.append(char)

    return ''.join(result)
